def ProperIdeal.{p} :
  forall (Poly : Sort p), forall (one : Poly), forall (I : forall (f : Poly), Prop), Prop :=
  fun Poly => fun one => fun I => HnsNot (I one)

def ZeroSet.{a,p,u} :
  forall (K : Sort u), forall (zero : K), forall (Poly : Sort p), forall (Point : Sort a), forall (eval : forall (f : Poly), forall (x : Point), K), forall (I : forall (f : Poly), Prop), forall (x : Point), Prop :=
